public class Solution {
    public ListNode mergeTwoLists(ListNode l1, ListNode l2) {
        ListNode dummy = new ListNode(0);  // sentinel head
        ListNode tail = dummy;

        while (l1 != null && l2 != null) {
            if (l1.val <= l2.val) {
                tail.next = l1;
                l1 = l1.next;
            } else {
                tail.next = l2;
                l2 = l2.next;
            }
            tail = tail.next;  // advance tail
        }

        tail.next = (l1 != null) ? l1 : l2;  // attach remaining
        return dummy.next;  // skip the sentinel
    }
}

public class Solution {
    public ListNode removeNthFromEnd(ListNode head, int n) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode fast = dummy, slow = dummy;

        // Advance fast n+1 steps (creates gap of n between fast and slow)
        for (int i = 0; i <= n; i++)
            fast = fast.next;

        // Move both until fast reaches null
        while (fast != null) {
            slow = slow.next;
            fast = fast.next;
        }

        // slow is just before the node to remove
        slow.next = slow.next.next;
        return dummy.next;
    }
}

