public class Solution {
    public Node flatten(Node head) {
        Node curr = head;
        while (curr != null) {
            if (curr.child != null) {
                Node child = curr.child;
                Node next  = curr.next;
                // Find tail of child list
                Node tail = child;
                while (tail.next != null) tail = tail.next;
                // Splice: curr → child → (end of child) → next
                curr.next  = child;  child.prev = curr;
                tail.next  = next;   if (next != null) next.prev = tail;
                curr.child = null;
            }
            curr = curr.next;
        }
        return head;
    }
}
